<?php
 declare(strict_types=1);
require __DIR__.'/app.php';
require __DIR__.'/training-storage.php';
require __DIR__.'/training-permissions.php';
require __DIR__.'/training-receipt-service.php';
require __DIR__.'/training-reward-service.php';
$config=lqr_config();$state=lqr_load_state();$userId=lqr_current_user_id($config);$user=lqr_get_user($state,$config,$userId);$message='';$error='';try{tcl_require_training_admin($user);}catch(Throwable $e){$error=$e->getMessage();}
if(!$error&&($_SERVER['REQUEST_METHOD']??'GET')==='POST'&&($_POST['tcl_action']??'')==='review'){try{$decision=(string)($_POST['decision']??'');$submissionId=(string)($_POST['submission_id']??'');$note=(string)($_POST['reviewer_note']??'');tcl_review_submission($submissionId,$decision,$note,$user);$message='Submission reviewed: '.tcl_status_label($decision);}catch(Throwable $e){$error=$e->getMessage();}}
$pending=$error?[]:tcl_pending_submissions();$submissions=$pending;
?><!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Admin Training Review</title><link rel="stylesheet" href="assets/training-lab.css"></head><body class="tcl-app"><div class="tcl-shell"><aside class="tcl-sidebar"><a class="tcl-brand" href="training-lab.php"><span class="tcl-logo">MG</span><span><strong>Microgifter</strong><span>Review Queue</span></span></a><nav class="tcl-nav"><a href="training-lab.php"><span class="tcl-nav-icon">⌂</span><span>Dashboard</span></a><a href="training-campaigns.php"><span class="tcl-nav-icon">◆</span><span>Campaigns</span></a><a class="active" href="admin-training-review.php"><span class="tcl-nav-icon">✓</span><span>Review Queue</span></a><a href="admin-training-receipts.php"><span class="tcl-nav-icon">▣</span><span>Receipts</span></a><a href="index.php"><span class="tcl-nav-icon">LQ</span><span>Local Quest</span></a></nav></aside><main class="tcl-main"><header class="tcl-topbar"><button class="tcl-mobile-menu">☰</button><div class="tcl-search">⌕ <span>Review pending proof submissions</span></div></header><section class="tcl-page-head"><div><span class="tcl-eyebrow">Admin Proof Review</span><h1>Review Queue</h1><p>Reviewer access is required. POST actions use the existing Local Quest CSRF protection from app.php.</p></div><a class="tcl-btn" href="admin-training-receipts.php">Receipts</a></section><?php if($message):?><div class="tcl-card" style="margin-bottom:16px"><span class="tcl-pill is-success"><?=lqr_h($message)?></span></div><?php endif;?><?php if($error):?><div class="tcl-card" style="margin-bottom:16px"><span class="tcl-pill is-danger"><?=lqr_h($error)?></span></div><?php endif;?><section class="tcl-grid cols-4"><div class="tcl-card tcl-kpi"><span>Pending</span><strong><?=count($pending)?></strong><small>Need review</small></div><div class="tcl-card tcl-kpi"><span>Receipts</span><strong><?=count($error?[]:tcl_all_receipts())?></strong><small>Verified actions</small></div><div class="tcl-card tcl-kpi"><span>Reward Issues</span><strong><?=count($error?[]:tcl_all_reward_issues())?></strong><small>Generated records</small></div><div class="tcl-card tcl-kpi"><span>Access</span><strong style="font-size:20px"><?=$error?'Blocked':'Reviewer'?></strong><small>Permission checked</small></div></section><section class="tcl-card" style="margin-top:22px"><div class="tcl-card-head"><div><h2>Pending submissions</h2><p>Approve, reject, or request resubmission.</p></div><span class="tcl-pill is-warning">Manual Review</span></div><div class="tcl-step-list"><?php if(!$submissions):?><div class="tcl-empty">No pending submissions available.</div><?php endif;?><?php foreach($submissions as $sub):$campaign=tcl_storage_campaign_by_slug((string)$sub['campaign_slug']);$stored=(string)($sub['file']['stored_filename']??'');?><div class="tcl-step <?=lqr_h((string)$sub['status'])?>"><span class="tcl-step-index">⇧</span><div><h4><?=lqr_h((string)($campaign['title']??$sub['campaign_slug']))?> · <?=lqr_h((string)$sub['task_slug'])?></h4><p>Attempt <?=number_format((int)$sub['attempt_number'])?> · <?=lqr_h((string)$sub['submitted_at'])?> · <?=lqr_h((string)($sub['file']['original_filename']??'text note'))?></p><div class="tcl-tags"><span class="tcl-pill <?=tcl_status_class((string)$sub['status'])?>"><?=lqr_h(tcl_status_label((string)$sub['status']))?></span><?php if($stored):?><a class="tcl-pill is-info" href="training-proof-file.php?file=<?=urlencode($stored)?>" target="_blank" rel="noopener">View proof</a><?php endif;?><span class="tcl-pill is-muted"><?=lqr_h((string)$sub['participant_note'])?></span></div><form method="post" style="margin-top:12px;display:grid;gap:10px"><input type="hidden" name="tcl_action" value="review"><input type="hidden" name="submission_id" value="<?=lqr_h((string)$sub['id'])?>"><textarea name="reviewer_note" rows="2" placeholder="Reviewer note" style="width:100%;border:1px solid #dbe4f0;border-radius:12px;padding:10px"></textarea><div class="tcl-actions"><button class="tcl-btn primary" name="decision" value="approved">Approve</button><button class="tcl-btn" name="decision" value="needs_resubmission">Request Resubmission</button><button class="tcl-btn" name="decision" value="rejected">Reject</button></div></form></div></div><?php endforeach;?></div></section></main></div><script src="assets/training-lab.js"></script></body></html>
